# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
import boto3
import time
import os

app = Flask(__name__)

# Configure S3
s3 = boto3.client('s3')
bucket_name = 'your-s3-bucket-name'

# Configure Chrome options for headless operation
chrome_options = Options()
chrome_options.add_argument("--headless")
chrome_options.add_argument("--no-sandbox")
chrome_options.add_argument("--disable-dev-shm-usage")

# Setting the path for ChromeDriver
chrome_service = Service('/path/to/chromedriver')

@app.route('/screenshot', methods=['POST'])
def screenshot():
    data = request.get_json()
    url = data.get('url')

    if not url:
        return jsonify({'error': 'URL is required'}), 400

    # Create a new instance of Chrome
    with webdriver.Chrome(service=chrome_service, options=chrome_options) as driver:
        driver.get(url)
        time.sleep(2)  # Wait for the page to load

        # Take a screenshot
        screenshot_path = '/tmp/screenshot.png'
        driver.save_screenshot(screenshot_path)

    # Upload to S3
    s3.upload_file(screenshot_path, bucket_name, f'screenshots/{int(time.time())}.png')

    # Clean up
    os.remove(screenshot_path)

    return jsonify({'message': 'Screenshot captured', 'url': f'https://{bucket_name}.s3.amazonaws.com/screenshots/{int(time.time())}.png'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)